module top_module(
	input clk,
	input load,
	input shift_left,
	input shift_right,
	input [19:0] load_value,
	output reg [19:0] q);
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (load)
		q <= load_value;
	else if (shift_left)
		q <= q << 1;
	else if (shift_right)
		q <= q >> 1;
end

endmodule
